import{_ as n,o as h,c as i,ag as t}from"./chunks/framework.BZohXCq9.js";const s=JSON.parse('{"title":"[Admin] Kho tính năng: Cấu hình Tìm kiếm (Search Config CMS)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/03-kho-tinh-nang/tim-kiem-kham-pha/admin-configs.md","filePath":"99-tham-khao/archive/03-kho-tinh-nang/tim-kiem-kham-pha/admin-configs.md"}'),o={name:"99-tham-khao/archive/03-kho-tinh-nang/tim-kiem-kham-pha/admin-configs.md"};function e(l,a,r,u,m,c){return h(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="admin-kho-tinh-nang-cau-hinh-tim-kiem-search-config-cms" tabindex="-1">[Admin] Kho tính năng: Cấu hình Tìm kiếm (Search Config CMS) <a class="header-anchor" href="#admin-kho-tinh-nang-cau-hinh-tim-kiem-search-config-cms" aria-label="Permalink to &quot;[Admin] Kho tính năng: Cấu hình Tìm kiếm (Search Config CMS)&quot;">​</a></h1><p>Quản lý tìm kiếm và nội dung gợi ý thông minh dành cho quản trị viên.</p><h2 id="_1-cau-hinh-hot-keywords-goi-y" tabindex="-1">1. Cấu hình &quot;Hot Keywords&quot; (Gợi ý) <a class="header-anchor" href="#_1-cau-hinh-hot-keywords-goi-y" aria-label="Permalink to &quot;1. Cấu hình &quot;Hot Keywords&quot; (Gợi ý)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Danh sách từ khóa xu hướng (e.g. Phú Quốc, Tour Hè 2026).</li><li>Quản lý gợi ý dựa trên từ khóa thực tế của người dùng.</li></ul></li></ul><h2 id="_2-quan-ly-tag-phan-loai-labels" tabindex="-1">2. Quản lý Tag &amp; Phân loại (Labels) <a class="header-anchor" href="#_2-quan-ly-tag-phan-loai-labels" aria-label="Permalink to &quot;2. Quản lý Tag &amp; Phân loại (Labels)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Gắn nhãn cho Tour (e.g. Sale, Mới, Hot, Best Seller).</li><li>Phân chia danh mục du lịch (Mạo hiểm, Nghỉ dưỡng).</li></ul></li></ul><h2 id="_3-quan-ly-featured-popular-ranking" tabindex="-1">3. Quản lý Featured &amp; Popular (Ranking) <a class="header-anchor" href="#_3-quan-ly-featured-popular-ranking" aria-label="Permalink to &quot;3. Quản lý Featured &amp; Popular (Ranking)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Thay đổi <code>sortOrder</code> cho Tour/Điểm đến nổi bật trên trang chủ.</li><li>Cấu hình thứ tự của bộ lọc.</li></ul></li></ul><h2 id="_4-log-tim-kiem-search-logs" tabindex="-1">4. Log Tìm kiếm (Search Logs) <a class="header-anchor" href="#_4-log-tim-kiem-search-logs" aria-label="Permalink to &quot;4. Log Tìm kiếm (Search Logs)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: Xem danh sách các từ khóa mà khách hàng tìm kiếm nhiều nhất nhưng chưa có kết quả (No result keywords).</li></ul><hr><p><em>Cơ sở tối ưu hóa nội dung SEO &amp; Search.</em></p>',12)])])}const d=n(o,[["render",e]]);export{s as __pageData,d as default};
